/ozyegin-antropoloji-bolumu/#webpage"},"publisher":{"@id":"https://roadtostudy.com/#person"},"inLanguage":"tr","mainEntityOfPage":{"@id":"https://roadtostudy.com/ozyegin-antropoloji-bolumu/#webpage"}},{"@type":"VideoObject","name":"Özyeğin Üniversitesi Antropoloji Bölümü - RoadtoStudy","description":"Enjoy the videos and music you love, upload original content, and share it all with friends, family, and the world on YouTube.","uploadDate":"2025-07-02T12:59:42+03:00","thumbnailUrl":"https://roadtostudy.com/wp-content/uploads/2025/07/ozyegin-universitesi-antropoloji-bolumu.webp","embedUrl":"https://www.youtube.com/embed/jPjU2McMfSY","isFamilyFriendly":"True","@id":"https://roadtostudy.com/ozyegin-antropoloji-bolumu/#schema-9022","isPartOf":{"@id":"https://roadtostudy.com/ozyegin-antropoloji-bolumu/#webpage"},"publisher":{"@id":"https://roadtostudy.com/#person"},"inLanguage":"tr","mainEntityOfPage":{"@id":"https://roadtostudy.com/ozyegin-antropoloji-bolumu/#webpage"}}]}]}'), '$.content_html', '<p class="wp-block-paragraph"></p>



<figure class="wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio"><div class="wp-block-embed__wrapper">
